)

INSERT INTO PAYMENT (
    PAYMENT_ID, ORDER_ID, PG_PROVIDER, PG_TID, AMOUNT, STATUS, PAID_AT
) VALUES (
    PAYMENT_SEQ.NEXTVAL, #{merchantUid}, #{payMethod}, #{impUid}, #{amount}, 'SUCCESS', SYSDATE
)

